import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/launch-targets.DIrU2w_6.js";const s=JSON.parse(`{"title":"Das Spiel in VS Code ausführen","description":"Lerne, wie man eine Minecraft-Instanz aus Visual Studio Code heraus startet.","frontmatter":{"title":"Das Spiel in VS Code ausführen","description":"Lerne, wie man eine Minecraft-Instanz aus Visual Studio Code heraus startet.","authors":["dicedpixels"],"prev":{"text":"Ein Projekt in VS Code öffnen","link":"./opening-a-project"},"next":{"text":"Quellcode in VS Code generieren","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"de_de/develop/getting-started/vscode/launching-the-game.md","filePath":"translated/de_de/develop/getting-started/vscode/launching-the-game.md","lastUpdated":1770561656000}`);var c={name:`de_de/develop/getting-started/vscode/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Das Spiel in VS Code ausführen <a class="header-anchor" href="#h1" aria-label="Permalink to “Das Spiel in VS Code ausführen”">​</a></h1><p>Die Fabric-Toolchain lässt sich in Visual Studio Code integrieren und bietet eine bequeme Möglichkeit, eine Spielinstanz auszuführen, um deinen Mod zu testen und zu debuggen.</p><h2 id="generating-launch-targets" tabindex="-1">Ausführungsziele generieren <a class="header-anchor" href="#generating-launch-targets" aria-label="Permalink to “Ausführungsziele generieren”">​</a></h2><p>Um das Spiel mit aktivierter Debugging-Unterstützung auszuführen, musst du Ausführungsziele generieren, indem du die <code>vscode</code>-Gradle-Aufgabe ausführst.</p><p>Dies kann über die Gradle-Ansicht in Visual Studio Code erfolgen: Öffne diese und navigiere zu der <code>vscode</code>-Aufgabe unter <strong>Tasks</strong> &gt; <strong><code>ide</code></strong>. Doppelklicke oder verwende die Schaltfläche <strong>Run Task</strong>, um die Aufgabe auszuführen.</p><p><img src="/assets/develop/getting-started/vscode/gradle-vscode.png" alt="vscode-Aufgabe in der Gradle-Ansicht" loading="lazy"></p><p>Alternativ kannst du das Terminal direkt verwenden: Öffne ein neues Terminal über <strong>Terminal</strong> &gt; <strong>New Terminal</strong> und führe den folgenden Befehl aus:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vscode/terminal-vscode.png" alt="vscode-Aufgabe im Terminal" loading="lazy"></p><h3 id="using-launch-targets" tabindex="-1">Ausführungsziele verwenden <a class="header-anchor" href="#using-launch-targets" aria-label="Permalink to “Ausführungsziele verwenden”">​</a></h3><p>Sobald die Startziele generiert sind, kannst du sie verwenden, indem du die Ansicht <strong>Run and Debug</strong> öffnest, das gewünschte Ziel auswählst und die Schaltfläche <strong>Start Debugging</strong> (<kbd>F5</kbd>) drückst.</p><p><img src="/assets/develop/getting-started/vscode/launch-targets.png" alt="Ausführungsziele" loading="lazy"></p>`,12)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};